syntax = "proto3";

package order;

// 주문 상태
enum OrderStatus {
    UNKNOWN = 0;
    PENDING = 1;
    PROCESSING = 2;
    SHIPPED = 3;
    DELIVERED = 4;
    CANCELLED = 5;
}

// 주문 생성 요청
message CreateOrderRequest {
    string order_id = 1;
    string product_name = 2;
    int32 quantity = 3;
    double price = 4;
    string customer_id = 5;
}

// 주문 응답
message OrderResponse {
    string order_id = 1;
    string status = 2;
    double total_amount = 3;
    string timestamp = 4;
    repeated string messages = 5;
}

// 주문 추적 스트림 응답
message OrderTrackingEvent {
    string order_id = 1;
    string event = 2;
    string timestamp = 3;
    string location = 4;
}

// 배치 주문 요청 (클라이언트 스트리밍)
message BatchOrderRequest {
    string order_id = 1;
    string product_name = 2;
    int32 quantity = 3;
    double price = 4;
}

// 배치 처리 응답
message BatchOrderResponse {
    int32 total_orders = 1;
    int32 successful = 2;
    int32 failed = 3;
    double total_revenue = 4;
    repeated string errors = 5;
}

// 양방향 스트리밍용 주문 이벤트
message OrderEvent {
    string order_id = 1;
    string action = 2;  // "create", "track", "cancel"
    string data = 3;
}

// OrderService: 4가지 RPC 패턴
service OrderService {
    // 1. Unary: 단순 요청-응답
    rpc CreateOrder(CreateOrderRequest) returns (OrderResponse);

    // 2. Server Streaming: 서버에서 순차적으로 여러 응답 전송
    rpc TrackOrderStream(CreateOrderRequest) returns (stream OrderTrackingEvent);

    // 3. Client Streaming: 클라이언트에서 여러 요청 전송 후 집계 응답
    rpc ProcessBatchOrders(stream BatchOrderRequest) returns (BatchOrderResponse);

    // 4. Bidirectional Streaming: 양방향 실시간 통신
    rpc ProcessOrdersBidirectional(stream OrderEvent) returns (stream OrderResponse);
}

