syntax = "proto3";

package payment;

// 결제 방법
enum PaymentMethod {
    UNKNOWN = 0;
    CREDIT_CARD = 1;
    DEBIT_CARD = 2;
    DIGITAL_WALLET = 3;
    BANK_TRANSFER = 4;
}

// 결제 상태
enum PaymentStatus {
    PENDING = 0;
    APPROVED = 1;
    DECLINED = 2;
    REFUNDED = 3;
    FAILED = 4;
}

// 결제 요청
message PaymentRequest {
    string payment_id = 1;
    string order_id = 2;
    double amount = 3;
    PaymentMethod method = 4;
    string card_token = 5;
}

// 결제 응답
message PaymentResponse {
    string payment_id = 1;
    string order_id = 2;
    PaymentStatus status = 3;
    string transaction_id = 4;
    string timestamp = 5;
    string message = 6;
}

// 결제 검증 요청
message PaymentVerificationRequest {
    string payment_id = 1;
    string transaction_id = 2;
}

// 결제 영수증 (서버 스트리밍 응답)
message PaymentReceipt {
    string payment_id = 1;
    double amount = 2;
    string description = 3;
    string issued_at = 4;
}

// 환불 요청 (클라이언트 스트리밍)
message RefundRequest {
    string payment_id = 1;
    double amount = 2;
    string reason = 3;
}

// 환불 처리 결과
message RefundResponse {
    int32 total_refunds = 1;
    double total_amount = 2;
    int32 successful = 3;
    int32 failed = 4;
    repeated string details = 5;
}

// PaymentService: 4가지 RPC 패턴
service PaymentService {
    // 1. Unary: 단순 결제 처리
    rpc ProcessPayment(PaymentRequest) returns (PaymentResponse);

    // 2. Server Streaming: 결제 영수증 스트리밍 (매번 다른 영수증 발급)
    rpc GetPaymentReceipts(PaymentVerificationRequest) returns (stream PaymentReceipt);

    // 3. Client Streaming: 여러 환불 요청을 받아 배치 처리
    rpc ProcessRefunds(stream RefundRequest) returns (RefundResponse);

    // 4. Bidirectional Streaming: 실시간 결제 상태 추적
    rpc StreamPaymentStatus(stream PaymentRequest) returns (stream PaymentResponse);
}

