syntax = "proto3";

package delivery;

// 배송 상태
enum DeliveryStatus {
    UNKNOWN = 0;
    PENDING = 1;
    PICKED_UP = 2;
    IN_TRANSIT = 3;
    OUT_FOR_DELIVERY = 4;
    DELIVERED = 5;
    FAILED = 6;
    RETURNED = 7;
}

// 배송 요청
message DeliveryRequest {
    string delivery_id = 1;
    string order_id = 2;
    string address = 3;
    string recipient_name = 4;
    double weight = 5;
}

// 배송 응답
message DeliveryResponse {
    string delivery_id = 1;
    string order_id = 2;
    DeliveryStatus status = 3;
    string tracking_number = 4;
    string estimated_arrival = 5;
    string message = 6;
}

// 배송 위치 업데이트
message DeliveryLocationUpdate {
    string delivery_id = 1;
    double latitude = 2;
    double longitude = 3;
    string timestamp = 4;
    string address = 5;
}

// 배송 업데이트 요청
message DeliveryUpdateRequest {
    string delivery_id = 1;
}

// 배송 피드백 (클라이언트 스트리밍)
message DeliveryFeedback {
    string delivery_id = 1;
    int32 rating = 2;
    string comment = 3;
}

// 배송 피드백 처리 결과
message DeliveryFeedbackResponse {
    int32 total_feedbacks = 1;
    double average_rating = 2;
    int32 positive = 3;
    int32 negative = 4;
    repeated string insights = 5;
}

// 배송 이벤트 (양방향 스트리밍)
message DeliveryEvent {
    string delivery_id = 1;
    string event_type = 2;  // "update", "delay", "failure"
    string details = 3;
}

// DeliveryService: 4가지 RPC 패턴
service DeliveryService {
    // 1. Unary: 배송 요청
    rpc CreateDelivery(DeliveryRequest) returns (DeliveryResponse);

    // 2. Server Streaming: 배송 위치를 실시간 스트리밍
    rpc StreamDeliveryLocation(DeliveryUpdateRequest) returns (stream DeliveryLocationUpdate);

    // 3. Client Streaming: 여러 배송 피드백 수집
    rpc SubmitDeliveryFeedbacks(stream DeliveryFeedback) returns (DeliveryFeedbackResponse);

    // 4. Bidirectional Streaming: 실시간 배송 상태 양방향 통신
    rpc TrackDeliveryRealtime(stream DeliveryEvent) returns (stream DeliveryResponse);
}

